	.TITLE	TSCROLL	.PROC	M680002	.REF	DRIVERS	.REF	LIB	.REF	SM8	.REF	SCROLL	.LOC	0OSC1:	.BLKB	LSCVAROSC2:	.BLKB	LSCVARLGVAR:	.LOC	0START:	LOAD.L	A6,#R16"VAR	LOAD.W	D3,#2	.W	LIB,?MOUSE	LOAD.L	A3,#R16"NAME	LOAD.W	D3,#SCROLL_FIRST	.W	LIB_OPEN	LOAD.L	A5,#(A6)+OSC1	LOAD.W	(A5)+OSCDEBL,#600	LOAD.W	(A5)+OSCDEBO,#10	LOAD.W	(A5)+OSCHTR,#300	LOAD.W	(A5)+OSCHTV,#5000	CLR.B	(A5)+OSCHOR	SET.B	(A5)+OSCPAGE	.W	SCROLL_DRAW	LOAD.W	(A5)+OSCPOSV,#5000/2	.W	SCROLL_UPDATE	LOAD.W	(A5)+OSCINC,#5000/10	LOAD.L	A5,#(A6)+OSC2	LOAD.W	(A5)+OSCDEBL,#310	LOAD.W	(A5)+OSCDEBO,#0	LOAD.W	(A5)+OSCHTR,#600	LOAD.W	(A5)+OSCHTV,#5000	SET.B	(A5)+OSCHOR	CLR.B	(A5)+OSCPAGE	.W	SCROLL_DRAW	LOAD.W	(A5)+OSCPOSV,#5000/2	.W	SCROLL_UPDATE	LOAD.W	(A5)+OSCINC,#5000/1040$:	.W	LIB,?GETCAR	COMP.W	D3,#END	JUMP,EQ	90$	COMP.W	D3,#KEYMGP	JUMP,NE 40$50$:	.W	LIB,?IFMOUSE	LOAD.L	A5,#(A6)+OSC1	.W	SCROLL_MOVE	JUMP,EQ 70$	LOAD.L	A5,#(A6)+OSC2	.W	SCROLL_MOVE	JUMP,EQ 70$	LOAD.B	D3,#BIPLIT	.W	LIB,?BEEP	JUMP	40$70$:	CLR.L	D3	.W	LIB,?SETCURS	.W	LIB,?AFTIM	.B	NOCURS,NOEFLI	.ASCIZ	"X="	.EVEN	CLR.L	D4	LOAD.W	D4,(A6)+OSC2+OSCPOSV	LOAD.W	D3,#8	CLR.W	D2	.W	LIB,?AFDEC	.W	LIB,?AFCR	.W	LIB,?AFTIM	.ASCIZ	"Y="	.EVEN	CLR.L	D4	LOAD.W	D4,(A6)+OSC1+OSCPOSV	LOAD.W	D3,#8	CLR.W	D2	.W	LIB,?AFDEC	JUMP	40$90$:	EXITNAME:	.ASCIZ	"SCROLL"	.EVENVAR:	.BLKB	LGVAR	.END	START